260→export const repostService = async(sourceJournalId, caption, userId) => {
261→    if(!sourceJournalId || !userId){
262→        throw new AppError(400, 'sourceJournalId or userId is undefined');
263→    }
264→
265→    if(caption && caption.length > 280){
266→        throw new AppError(400, 'caption must be 280 characters or less');
267→    }
268→
269→    // Fetch source journal
270→    const {data: sourceJournal, error: errorSourceJournal} = await supabase
271→        .from('journals')
272→        .select('id, title, user_id, privacy, is_repost, repost_source_journal_id')
273→        .eq('id', sourceJournalId)
274→        .maybeSingle();
275→
276→    if(errorSourceJournal){
277→        console.error('supabase error while fetching source journal:', errorSourceJournal.message);
278→        throw new AppError(500, 'supabase error while fetching source journal');
279→    }
280→
281→    if(!sourceJournal){
282→        throw new AppError(404, 'source journal not found');
283→    }
284→
285→    if(sourceJournal.privacy !== 'public'){
286→        throw new AppError(403, 'cannot repost a private post');
287→    }
288→
289→    if(sourceJournal.user_id === userId){
290→        throw new AppError(403, 'cannot repost your own post');
291→    }
292→
293→    // If reposting a repost, follow chain to the ultimate original
294→    let ultimateSourceId = sourceJournalId;
295→    let ultimateSourceUserId = sourceJournal.user_id;
296→    let ultimateSourceTitle = sourceJournal.title;
297→
298→    if(sourceJournal.is_repost && sourceJournal.repost_source_journal_id){
299→        const {data: originalJournal, error: errorOriginal} = await supabase
300→            .from('journals')
301→            .select('id, title, user_id, privacy')
302→            .eq('id', sourceJournal.repost_source_journal_id)
303→            .maybeSingle();
304→
305→        if(errorOriginal){
306→            console.error('supabase error fetching original:', errorOriginal.message);
307→            throw new AppError(500, 'supabase error while fetching original post');
308→        }
309→        if(!originalJournal){
310→            throw new AppError(404, 'original post no longer exists');
311→        }
312→        if(originalJournal.privacy !== 'public'){
313→            throw new AppError(403, 'cannot repost a private post');
314→        }
315→        if(originalJournal.user_id === userId){
316→            throw new AppError(403, 'cannot repost your own post');
317→        }
318→
319→        ultimateSourceId = originalJournal.id;
320→        ultimateSourceUserId = originalJournal.user_id;
321→        ultimateSourceTitle = originalJournal.title;
322→    }
323→
324→    // Check for duplicate repost
325→    const {data: existingRepost, error: errorExisting} = await supabase
326→        .from('journals')
327→        .select('id')
328→        .eq('user_id', userId)
329→        .eq('repost_source_journal_id', ultimateSourceId)
330→        .eq('is_repost', true)
331→        .maybeSingle();
332→
333→    if(errorExisting){
334→        console.error('supabase error while checking existing repost:', errorExisting.message);
335→        throw new AppError(500, 'supabase error while checking existing repost');
336→    }
337→
338→    if(existingRepost){
339→        throw new AppError(409, 'you have already reposted this post');
340→    }
341→
342→    const repostTitle = `Repost: ${ultimateSourceTitle || 'Untitled'}`;
343→
344→    const {data: insertedRepost, error: errorInsertRepost} = await supabase
345→        .from('journals')
346→        .insert({
347→            user_id: userId,
348→            is_repost: true,
349→            repost_source_journal_id: ultimateSourceId,
350→            repost_caption: caption || null,
351→            post_type: 'text',
352→            content: null,
353→            title: repostTitle.length > 255 ? repostTitle.substring(0, 255) : repostTitle,
354→            privacy: 'public'
355→        })
356→        .select('id')
357→        .single();
358→
359→    if(errorInsertRepost){
360→        console.error('supabase error while inserting repost:', errorInsertRepost.message);
361→        throw new AppError(500, 'supabase error while inserting repost');
362→    }
363→
364→    // Notify the original author (skip if self)
365→    const isOwnContent = userId === ultimateSourceUserId;
366→    if(!isOwnContent){
367→        const {error: errorNotif} = await supabase
368→            .from('notifications')
369→            .insert({
370→                sender_id: userId,
371→                receiver_id: ultimateSourceUserId,
372→                journal_id: ultimateSourceId,
373→                repost_journal_id: insertedRepost.id,
374→                type: 'repost',
375→                read: false
376→            });
377→
378→        if(errorNotif){
379→            console.error('supabase error while inserting repost notification:', errorNotif.message);
380→        }
381→    }
382→
383→    return {message: 'repost created', repostId: insertedRepost.id, sourceJournalId: ultimateSourceId};
384→}
