  1→import supabase from "./supabase.js";
  2→import { createMediaResponsePayload } from "../utils/mediaVariants.js";
  3→
  4→const NOTIFICATION_LIMIT_MIN = 1;
  5→const NOTIFICATION_LIMIT_MAX = 20;
  6→const NOTIFICATION_DEFAULT_LIMIT = 5;
  7→
  8→const NOTIFICATION_JOURNAL_SELECT = `
  9→    id,
 10→    sender_id,
 11→    receiver_id,
 12→    journal_id,
 13→    repost_journal_id,
 14→    type,
 15→    reaction_type,
 16→    read,
 17→    created_at,
 18→    journals!journal_id(
 19→        title,
 20→        preview_text,
 21→        thumbnail_url,
 22→        created_at,
 23→        users(id, name, image_url, badge)
 24→    ),
 25→    users!sender_id(id, name, image_url, badge)
 26→`;
 27→
 28→const NOTIFICATION_OPINION_SELECT = `
 29→    id,
 30→    sender_id,
 31→    receiver_id,
 32→    opinion_id,
 33→    read,
 34→    created_at,
 35→    opinions!opinion_id(id, opinion, user_id, created_at),
 36→    users!sender_id(id, name, image_url, badge)
 37→`;
 38→
 39→export const parseLimitWithinRange = (value, min = NOTIFICATION_LIMIT_MIN, max = NOTIFICATION_LIMIT_MAX, fallback = NOTIFICATION_DEFAULT_LIMIT) => {
 40→    const parsed = Number.parseInt(value, 10);
 41→    if (Number.isNaN(parsed)) return fallback;
 42→    if (parsed < min || parsed > max) return null;
 43→    return parsed;
 44→};
 45→
 46→const decorateNotificationMedia = (notification) => {
 47→    if (!notification || typeof notification !== 'object') return notification;
 48→
 49→    const senderAvatarMedia = createMediaResponsePayload('avatars', notification.users?.image_url, 'card');
 50→    const journalThumbnailMedia = createMediaResponsePayload('journal-images', notification.journals?.thumbnail_url, 'card');
 51→    const journalUserAvatarMedia = createMediaResponsePayload('avatars', notification.journals?.users?.image_url, 'card');
 52→
 53→    return {
 54→        ...notification,
 55→        users: notification.users ? {
 56→            ...notification.users,
 57→            image_url: senderAvatarMedia?.preferred_url || notification.users.image_url || null,
 58→            avatar_media: senderAvatarMedia
 59→        } : notification.users,
 60→        journals: notification.journals ? {
 61→            ...notification.journals,
 62→            thumbnail_url: journalThumbnailMedia?.preferred_url || notification.journals.thumbnail_url || null,
 63→            thumbnail_media: journalThumbnailMedia,
 64→            users: notification.journals.users ? {
 65→                ...notification.journals.users,
 66→                image_url: journalUserAvatarMedia?.preferred_url || notification.journals.users.image_url || null,
 67→                avatar_media: journalUserAvatarMedia
 68→            } : notification.journals.users
 69→        } : notification.journals
 70→    };
 71→};
 72→
 73→/**
 74→ * Unified notification fetcher.
 75→ * @param {string} userId
 76→ * @param {{ limit: number, before?: string, unreadOnly?: boolean }} options
 77→ */
 78→export const getNotificationsService = async (userId, { limit, before, unreadOnly = false }) => {
 79→    const fetchLimit = limit + 1;
 80→
 81→    let journalQuery = supabase
 82→        .from('notifications')
 83→        .select(NOTIFICATION_JOURNAL_SELECT)
 84→        .eq('receiver_id', userId)
 85→        .order('created_at', { ascending: false })
 86→        .order('id', { ascending: false })
 87→        .limit(fetchLimit);
 88→
 89→    let opinionQuery = supabase
 90→        .from('notification_opinions')
 91→        .select(NOTIFICATION_OPINION_SELECT)
 92→        .eq('receiver_id', userId)
 93→        .order('created_at', { ascending: false })
 94→        .order('id', { ascending: false })
 95→        .limit(fetchLimit);
 96→
 97→    if (unreadOnly) {
 98→        journalQuery = journalQuery.eq('read', false);
 99→        opinionQuery = opinionQuery.eq('read', false);
100→    }
101→
102→    if (before) {
103→        journalQuery = journalQuery.lt('created_at', before);
104→        opinionQuery = opinionQuery.lt('created_at', before);
105→    }
106→
107→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
108→
109→    if (journalResult.error) {
110→        console.error('error fetching notifications:', journalResult.error);
111→        throw { status: 500, error: 'error fetching data from notification table' };
112→    }
113→    if (opinionResult.error) {
114→        console.error('error fetching opinion notifications:', opinionResult.error);
115→        throw { status: 500, error: 'error fetching data from notification_opinions table' };
116→    }
117→
118→    const journalNotifs = (journalResult.data || []).map(n => ({ ...n, source: 'journal' }));
119→    const opinionNotifs = (opinionResult.data || []).map(n => ({ ...n, source: 'opinion' }));
120→
121→    const merged = [...journalNotifs, ...opinionNotifs]
122→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
123→
124→    // Likes/bookmarks lookup only for journal notifications
125→    const journalIds = [...new Set(
126→        merged
127→            .filter(n => n.source === 'journal')
128→            .map(n => n.journal_id)
129→            .filter(Boolean)
130→    )];
131→
132→    let hasLikedResult = [];
133→    let hasBookMarkedResult = [];
134→    if (journalIds.length > 0) {
135→        const [hasLiked, hasBookMarked] = await Promise.all([
136→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
137→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
138→        ]);
139→
140→        if (hasLiked.error || hasBookMarked.error) {
141→            console.error('supabase error fetching likes/bookmarks:', hasLiked.error || hasBookMarked.error);
142→        }
143→        hasLikedResult = hasLiked.data || [];
144→        hasBookMarkedResult = hasBookMarked.data || [];
145→    }
146→
147→    const likedSet = new Set(hasLikedResult.map(l => l.journal_id));
148→    const bookmarkedSet = new Set(hasBookMarkedResult.map(b => b.journal_id));
149→
150→    const formatted = merged.map(notif => decorateNotificationMedia({
151→        ...notif,
152→        hasLiked: notif.source === 'journal' ? likedSet.has(notif.journal_id) : false,
153→        hasBookMarked: notif.source === 'journal' ? bookmarkedSet.has(notif.journal_id) : false
154→    }));
155→
156→    const hasMore = formatted.length > limit;
157→    const data = hasMore ? formatted.slice(0, limit) : formatted;
158→
159→    return { data, hasMore };
160→};
161→
162→export const getCountNotificationsService = async (userId) => {
163→    const { data, error } = await supabase.rpc('get_unread_notification_count', {
164→        p_user_id: userId,
165→    });
166→
167→    if (error) {
168→        console.error('get_unread_notification_count rpc error:', error.message);
169→        throw { status: 500, error: 'error fetching count in notifications table' };
170→    }
171→
172→    return { count: data ?? 0 };
173→};
174→
175→export const readNotificationService = async (userId, notifId, source) => {
176→    const tableName = source === 'opinion' ? 'notification_opinions' : 'notifications';
177→
178→    const { error } = await supabase
179→        .from(tableName)
180→        .update({ read: true })
181→        .eq('receiver_id', userId)
182→        .eq('id', notifId);
183→
184→    if (error) {
185→        console.error('error updating notification read status:', error);
186→        throw { status: 500, error: 'error updating the notification read status' };
187→    }
188→
189→    return { message: 'notification was read!' };
190→};
191→
192→export const deleteNotificationService = async (userId, notifId, source) => {
193→    if (!notifId) {
194→        throw { status: 400, error: 'notifId is required' };
195→    }
196→
197→    const tableName = source === 'opinion' ? 'notification_opinions' : 'notifications';
198→
199→    const { error } = await supabase
200→        .from(tableName)
201→        .delete()
202→        .eq('receiver_id', userId)
203→        .eq('id', notifId);
204→
205→    if (error) {
206→        console.error('supabase error while deleting notification:', error.message);
207→        throw { status: 500, error: 'supabase error while deleting notification' };
208→    }
209→
210→    return { message: 'success' };
211→};
212→
213→export { NOTIFICATION_LIMIT_MIN, NOTIFICATION_LIMIT_MAX, NOTIFICATION_DEFAULT_LIMIT };
