 28→const NOTIFICATION_OPINION_SELECT = `
 29→    id,
 30→    sender_id,
 31→    receiver_id,
 32→    opinion_id,
 33→    type,
 34→    read,
 35→    created_at,
 36→    opinions!opinion_id(id, opinion, user_id, created_at),
