288→export const repostService = async(sourceJournalId, caption, userId) => {
289→    if(!sourceJournalId || !userId){
290→        throw new AppError(400, 'sourceJournalId or userId is undefined');
291→    }
292→
293→    if(caption && caption.length > 280){
294→        throw new AppError(400, 'caption must be 280 characters or less');
295→    }
296→
297→    // Fetch source journal
298→    const {data: sourceJournal, error: errorSourceJournal} = await supabase
299→        .from('journals')
300→        .select('id, title, user_id, privacy, is_repost, repost_source_journal_id')
301→        .eq('id', sourceJournalId)
302→        .maybeSingle();
303→
304→    if(errorSourceJournal){
305→        console.error('supabase error while fetching source journal:', errorSourceJournal.message);
306→        throw new AppError(500, 'supabase error while fetching source journal');
307→    }
308→
309→    if(!sourceJournal){
310→        throw new AppError(404, 'source journal not found');
311→    }
312→
313→    if(sourceJournal.privacy !== 'public'){
314→        throw new AppError(403, 'cannot repost a private post');
315→    }
316→
317→    if(sourceJournal.user_id === userId){
318→        throw new AppError(403, 'cannot repost your own post');
319→    }
320→
321→    // If reposting a repost, follow chain to the ultimate original
322→    let ultimateSourceId = sourceJournalId;
323→    let ultimateSourceUserId = sourceJournal.user_id;
324→    let ultimateSourceTitle = sourceJournal.title;
325→
326→    if(sourceJournal.is_repost && sourceJournal.repost_source_journal_id){
327→        const {data: originalJournal, error: errorOriginal} = await supabase
328→            .from('journals')
329→            .select('id, title, user_id, privacy')
330→            .eq('id', sourceJournal.repost_source_journal_id)
331→            .maybeSingle();
332→
333→        if(errorOriginal){
334→            console.error('supabase error fetching original:', errorOriginal.message);
335→            throw new AppError(500, 'supabase error while fetching original post');
336→        }
337→        if(!originalJournal){
338→            throw new AppError(404, 'original post no longer exists');
339→        }
340→        if(originalJournal.privacy !== 'public'){
341→            throw new AppError(403, 'cannot repost a private post');
342→        }
343→        if(originalJournal.user_id === userId){
344→            throw new AppError(403, 'cannot repost your own post');
345→        }
346→
347→        ultimateSourceId = originalJournal.id;
348→        ultimateSourceUserId = originalJournal.user_id;
349→        ultimateSourceTitle = originalJournal.title;
350→    }
351→
352→    // Check for duplicate repost
353→    const {data: existingRepost, error: errorExisting} = await supabase
354→        .from('journals')
355→        .select('id')
356→        .eq('user_id', userId)
357→        .eq('repost_source_journal_id', ultimateSourceId)
358→        .eq('is_repost', true)
359→        .maybeSingle();
360→
361→    if(errorExisting){
362→        console.error('supabase error while checking existing repost:', errorExisting.message);
363→        throw new AppError(500, 'supabase error while checking existing repost');
364→    }
365→
366→    if(existingRepost){
367→        throw new AppError(409, 'you have already reposted this post');
368→    }
369→
370→    const repostTitle = `Repost: ${ultimateSourceTitle || 'Untitled'}`;
371→
372→    const {data: insertedRepost, error: errorInsertRepost} = await supabase
373→        .from('journals')
374→        .insert({
375→            user_id: userId,
376→            is_repost: true,
377→            repost_source_journal_id: ultimateSourceId,
378→            repost_caption: caption || null,
379→            post_type: 'text',
380→            content: null,
381→            title: repostTitle.length > 255 ? repostTitle.substring(0, 255) : repostTitle,
382→            privacy: 'public'
383→        })
384→        .select('id')
385→        .single();
386→
387→    if(errorInsertRepost){
388→        console.error('supabase error while inserting repost:', errorInsertRepost.message);
389→        throw new AppError(500, 'supabase error while inserting repost');
390→    }
391→
392→    // Notify the original author (skip if self)
393→    const isOwnContent = userId === ultimateSourceUserId;
394→    if(!isOwnContent){
395→        const {error: errorNotif} = await supabase
396→            .from('notifications')
397→            .insert({
398→                sender_id: userId,
399→                receiver_id: ultimateSourceUserId,
400→                journal_id: ultimateSourceId,
401→                repost_journal_id: insertedRepost.id,
402→                type: 'repost',
403→                read: false
404→            });
405→
406→        if(errorNotif){
407→            console.error('supabase error while inserting repost notification:', errorNotif.message);
408→        }
409→    }
410→
411→    return {message: 'repost created', repostId: insertedRepost.id, sourceJournalId: ultimateSourceId};
412→}
